mapper.select:
/* getStockInspectionOrder */ select ROW_NUMBER() OVER(order by A.PHYSOKY, A.PHYSOIT , A.WAREKEY, A.AREAKEY, A.ZONEKEY, A.LOCAKEY, A.SKUMKEY , C.SKUDESC, A.COMPKEY, A.OWNERKY, A.VENDKEY) as ROWNUM , A.COMPKEY as COMPKEY , ifnull(A.PHYSOKY, ' ') as PHYSOKY , ML.LOCANAM as LOCAKEY , A.SKUMKEY as SKUMKEY , C.SKUDESC as SKUDESC , A.SYSTQTY as SYSTQTY , A.SUOMKEY as SUOMKEY , date_format(NOW(), '%Y-%m-%d %H:%i:%s') as PRINTDAY , (select concat(WAREKEY, ' (', WHNAMLC, ')') from MWARMA where COMPKEY = A.COMPKEY and WAREKEY = A.WAREKEY) as WAREKEY , (select OWNAMLC from MOWRMA where COMPKEY = A.COMPKEY and OWNERKY = A.OWNERKY) as OWNERKY , concat(CEILING(MP.PACKQTY), '/', CEILING(A.SYSTQTY / MP.PACKQTY)) as BOXCNT from WPHYIT A inner join MSKUWC C on A.COMPKEY = C.COMPKEY and A.WAREKEY = C.WAREKEY and A.OWNERKY = C.OWNERKY and A.SKUMKEY = C.SKUMKEY inner join MLOCMA ML on ML.COMPKEY = A.COMPKEY and ML.WAREKEY = A.WAREKEY and ML.LOCAKEY = A.LOCAKEY left outer join SUSRMA U on U.COMPKEY = A.COMPKEY and U.USERACT = C.SKUAT01 left outer join MPAKMA MP on MP.COMPKEY = C.COMPKEY and MP.WAREKEY = C.WAREKEY and MP.TRUNTYP = C.TRUNTYP and MP.PACKKEY = C.PACKKEY where A.COMPKEY = #{compkey} and A.AREAKEY = 'STG' and A.PHYSOKY = #{physoky}
and A.PHYSOIT IN
#{item}
order by A.PHYSOKY, A.PHYSOIT , A.WAREKEY, A.AREAKEY, A.ZONEKEY, A.LOCAKEY, A.SKUMKEY , C.SKUDESC, A.COMPKEY, A.OWNERKY, A.VENDKEY

/* getPickingOrderByNormal */ select ROW_NUMBER() OVER(order by WT.COOUTKY, WT.COOUTIT) as ROWNUM , WT.COMPKEY , WT.COOUTKY , WT.SHPDCKY , ifnull(WT.ALLGRKY, ' ') as ALLGRKY , (select OWNAMLC from MOWRMA MO WHERE MO.COMPKEY = WT.COMPKEY and MO.OWNERKY = WT.OWNERKY) as OWNERKY , (select COMCDTX from V_MCODEM MC where MC.COMPKEY = WT.COMPKEY and MC.COMCDVL = WT.PICKTYP ) as PICKTYP , concat(WT.WAREKEY, ' (', (select WHNAMLC from MWARMA MW WHERE MW.COMPKEY = WT.COMPKEY and MW.WAREKEY = WT.WAREKEY), ')') as WAREKEY , WT.SKUMKEY , WT.SKUDESC , (select MZ.ZONENAM from MZONMA MZ where MZ.COMPKEY = WT.COMPKEY and MZ.WAREKEY = WT.WAREKEY and MZ.AREAKEY = WT.FRAREKY and MZ.ZONEKEY = WT.FRZONKY) as ZONENAM , (select ML.LOCANAM from MLOCMA ML where ML.COMPKEY = WT.COMPKEY and ML.WAREKEY = WT.WAREKEY and ML.AREAKEY = WT.FRAREKY and ML.ZONEKEY = WT.FRZONKY and ML.LOCAKEY = WT.FRLOCKY) as LOCANAM , SUM(WT.FORDQTY) AS FORDQTY , WT.FUOMEKY , date_format(NOW(), '%Y-%m-%d %H:%i:%s') as PRINTDAY , date_format(NOW(), '%Y-%m-%d') as SHPPDAY , MSP.UPCCODE , ifnull(CONCAT(CEILING(MSP.PACKQTY), '/', CEILING(WT.FORDQTY / MSP.PACKQTY)), '0/0') AS BOXCNT from WTAKIT WT inner join ( select MS.COMPKEY, MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY, MS.SKUDESC, MS.SUOMKEY, MS.UPCCODE, MS.TRUNTYP, MP.PACKKEY, MP.PACKQTY from MSKUWC MS left outer join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.WAREKEY = MS.WAREKEY and MP.TRUNTYP = MS.TRUNTYP and MP.PACKKEY = MS.PACKKEY ) MSP on WT.COMPKEY = MSP.COMPKEY and WT.WAREKEY = MSP.WAREKEY and WT.OWNERKY = MSP.OWNERKY and WT.SKUMKEY = MSP.SKUMKEY where WT.COMPKEY = #{compkey} and WT.WAREKEY = #{warekey} and WT.TASKSTS = #{tasksts} and WT.ALLGRKY = #{allgrky}
and WT.COOUTKY in
#{orditem}
and WT.COOUTKY = #{cooutky}
group by WT.COMPKEY, WT.WAREKEY, WT.OWNERKY, WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, WT.FRZONKY, WT.FRLOCKY, WT.PICKTYP order by WT.COOUTKY, WT.COOUTIT

/* getPickingOrderByReturn */ select ROW_NUMBER() OVER(order by WT.OERETKY, WT.OERETIT) as ROWNUM , WT.COMPKEY , WT.COOUTKY , WT.OERETKY , WT.SHPDCKY , ifnull(WT.ALLGRKY, ' ') as ALLGRKY , (select OWNAMLC from MOWRMA MO WHERE MO.COMPKEY = WT.COMPKEY and MO.OWNERKY = WT.OWNERKY) as OWNERKY , (select COMCDTX from V_MCODEM MC where MC.COMPKEY = WT.COMPKEY and MC.COMCDVL = WT.PICKTYP ) as PICKTYP , concat(WT.WAREKEY, ' (', (select WHNAMLC from MWARMA MW WHERE MW.COMPKEY = WT.COMPKEY and MW.WAREKEY = WT.WAREKEY), ')') as WAREKEY , WT.SKUMKEY , WT.SKUDESC , (select MZ.ZONENAM from MZONMA MZ where MZ.COMPKEY = WT.COMPKEY and MZ.WAREKEY = WT.WAREKEY and MZ.AREAKEY = WT.FRAREKY and MZ.ZONEKEY = WT.FRZONKY) as ZONENAM , (select ML.LOCANAM from MLOCMA ML where ML.COMPKEY = WT.COMPKEY and ML.WAREKEY = WT.WAREKEY and ML.AREAKEY = WT.FRAREKY and ML.ZONEKEY = WT.FRZONKY and ML.LOCAKEY = WT.FRLOCKY) as LOCANAM , SUM(WT.FORDQTY) AS FORDQTY , WT.FUOMEKY , date_format(NOW(), '%Y-%m-%d %H:%i:%s') as PRINTDAY , date_format(NOW(), '%Y-%m-%d') as SHPPDAY , MSP.UPCCODE , ifnull(CONCAT(CEILING(MSP.PACKQTY), '/', CEILING(WT.FORDQTY / MSP.PACKQTY)), '0/0') AS BOXCNT from WTAKIT WT inner join ( select MS.COMPKEY, MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY, MS.SKUDESC, MS.SUOMKEY, MS.UPCCODE, MS.TRUNTYP, MP.PACKKEY, MP.PACKQTY from MSKUWC MS left outer join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.WAREKEY = MS.WAREKEY and MP.TRUNTYP = MS.TRUNTYP and MP.PACKKEY = MS.PACKKEY ) MSP on WT.COMPKEY = MSP.COMPKEY and WT.WAREKEY = MSP.WAREKEY and WT.OWNERKY = MSP.OWNERKY and WT.SKUMKEY = MSP.SKUMKEY where WT.COMPKEY = #{compkey} and WT.WAREKEY = #{warekey} and WT.TASKSTS = #{tasksts} and WT.ALLGRKY = #{allgrky}
and WT.OERETKY in
#{orditem}
group by WT.COMPKEY, WT.WAREKEY, WT.OWNERKY, WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, WT.FRZONKY, WT.FRLOCKY, WT.FUOMEKY, WT.PICKTYP order by WT.OERETKY, WT.OERETIT

/* getPickingOrderItemByNormal */
select COUNT(A.SKU) as SKUNCNT
	 , SUM(A.STOCK) as STOTQTY
from (
	select count(WT.SKUMKEY) as SKU
		 , sum(WT.FORDQTY) as STOCK
	from WTAKIT WT
	where WT.COMPKEY = #{compkey}
	  and WT.WAREKEY = #{warekey}
	  and WT.TASKSTS = #{tasksts}
	  and WT.ALLGRKY = #{allgrky}

		and WT.COOUTKY in

			#{orditem}



		and WT.COOUTKY = #{cooutky}

	group by WT.SKUMKEY
) A

/* getPickingOrderItemByReturn */
select COUNT(A.SKU) as SKUNCNT
, SUM(A.STOCK) as STOTQTY
from (
	select count(WT.SKUMKEY) as SKU
	, sum(WT.FORDQTY) as STOCK
	from WTAKIT WT
	where WT.COMPKEY = #{compkey}
	  and WT.WAREKEY = #{warekey}
	  and WT.TASKSTS = #{tasksts}
	  and WT.ALLGRKY = #{allgrky}

		and WT.OERETKY in

			#{orditem}



		and WT.OERETKY = #{oeretky}

	group by WT.SKUMKEY
) A

/* getPileOrder */ select ROW_NUMBER() OVER(order by WT.TASKOKY, WT.TASKOIT) as ROWNUM , WT.COMPKEY , IFNULL(WT.TASKOKY, ' ') AS TASKOKY , WT.TASKOIT , CONCAT(WT.WAREKEY,' (', (SELECT WHNAMLC FROM MWARMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY ), ')') AS WAREKEY , (SELECT OWNAMLC FROM MOWRMA WHERE COMPKEY = WT.COMPKEY AND OWNERKY = WT.OWNERKY ) AS OWNERKY , WT.SKUMKEY , MS.SKUDESC , (SELECT LOCANAM FROM MLOCMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY AND AREAKEY = WT.FRAREKY AND ZONEKEY = WT.FRZONKY AND LOCAKEY = WT.FRLOCKY) AS FRLOCKY , (SELECT ZONENAM FROM MZONMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY AND AREAKEY = WT.TOAREKY AND ZONEKEY = WT.TOZONKY) AS TOZONKY , (SELECT LOCANAM FROM MLOCMA WHERE COMPKEY = WT.COMPKEY AND WAREKEY = WT.WAREKEY AND AREAKEY = WT.TOAREKY AND ZONEKEY = WT.TOZONKY AND LOCAKEY = WT.TOLOCKY) AS TOLOCKY , WT.FORDQTY , WT.FUOMEKY , MS.UPCCODE , DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s') AS PRINTDAY , CONCAT(CEILING(MP.PACKQTY), '/', CEILING(WT.FORDQTY/MP.PACKQTY)) AS BOXCNT from WTAKIT WT inner join WRCVIT WR on WR.RCVDCKY = WT.RCVDCKY and WR.COMPKEY = WT.COMPKEY and WR.WAREKEY = WT.WAREKEY and WR.RCVDCIT = WT.RCVDCIT inner join MSKUWC MS on MS.COMPKEY = WT.COMPKEY and MS.WAREKEY = WT.WAREKEY and MS.OWNERKY = WT.OWNERKY and MS.SKUMKEY = WT.SKUMKEY left join ( select COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, OWNERKY, SKUMKEY, LOTNMKY , sum(STOTQTY) as STOTQTY, sum(SALLQTY) as SALLQTY , sum(SINBQTY) as SINBQTY, sum(SOUBQTY) as SOUBQTY , sum(SBLOQTY) as SBLOQTY from WSTKKY where COMPKEY = #{compkey} and WAREKEY = #{warekey} and (STOTQTY-SBLOQTY) > 0 and SALLQTY = 0 and SINBQTY = 0 and SOUBQTY = 0 group by COMPKEY, WAREKEY, AREAKEY, ZONEKEY, LOCAKEY, OWNERKY, SKUMKEY, LOTNMKY ) WS on WS.COMPKEY = WT.COMPKEY and WS.WAREKEY = WT.WAREKEY and WS.AREAKEY = WT.TOAREKY and WS.ZONEKEY = WT.TOZONKY and WS.LOCAKEY = WT.TOLOCKY and WS.OWNERKY = WT.OWNERKY and WS.SKUMKEY = WT.SKUMKEY and WS.LOTNMKY = WT.LOTNMKY left outer join MPAKMA MP on MP.COMPKEY = WT.COMPKEY and MP.WAREKEY = WT.WAREKEY and MP.TRUNTYP = WT.TRUNTYP and MP.PACKKEY = MS.PACKKEY where WT.COMPKEY = #{compkey} and WT.WAREKEY = #{warekey} and WT.DOCCATE = #{doccate} and WT.DOCTYPE = #{doctype} and WT.TASKSTS = 'TASK' and WT.TOAREKY = 'STG' and WT.TASKOKY = #{taskoky}
and WT.TASKOIT IN
#{taskoit}
order by WT.TASKOKY, WT.TASKOIT

/* getPileOrderSummary */
select
	WAREKEY,
	TASKOKY,
	COUNT(DISTINCT SKUMKEY) AS SKUNCNT,
	SUM(FORDQTY) AS STOTQTY
 from WTAKIT WT
where WT.COMPKEY = #{compkey}
  and WT.DOCCATE = #{doccate} 
  and WT.DOCTYPE = #{doctype}
  and WT.TASKSTS = 'TASK' 
  and WT.TOAREKY = 'STG' 
  and WT.TASKOKY = #{taskoky}
  and WT.WAREKEY = #{warekey}

  and WT.TASKOIT IN

		#{taskoit}


group by WAREKEY, TASKOKY

/* getPalletLabel */ select WT.TRUNPID , WT.TRUNTYP , MT.TRUNNAM from WTAKIT WT inner join MTUTMA MT on MT.COMPKEY = WT.COMPKEY and MT.TRUNTYP = WT.TRUNTYP where WT.COMPKEY = #{compkey} and WT.TRUNPID IN
#{trunpid}
group by WT.TRUNPID, WT.TRUNTYP, MT.TRUNNAM

/* getShipOrder */ select ROW_NUMBER() OVER(order by SH.ALLGRKY, SH.COOUTIT) as ROWNUM , concat(SH.ALLGRKY , '|' , SH.COOUTKY , '|' , IFNULL(SH.DESTKEY , '')) as QRCDKEY , SH.COMPKEY , (select WHNAMLC from MWARMA where COMPKEY = SH.COMPKEY and WAREKEY = SH.WAREKEY) as WAREKEY , SH.OWNERKY , SH.DESTKEY , (select DENAMLC from MDESMA where COMPKEY = SH.COMPKEY and PTNRKEY = SH.CUSTKEY and DESTKEY = SH.DESTKEY) as DENAMLC , TS.SKUMKEY , TS.SKUDESC , TS.ALLGRKY , TS.PICKTYP , TS.TCMPQTY , date_format(NOW(), '%Y-%m-%d %H:%i:%s') as PRINTDAY , date_format(NOW(), '%Y-%m-%d') as SHPPDAY , SH.SUOMKEY , TS.COOUTKY , ifnull(CONCAT(CEILING(MSP.PACKQTY), '/', CEILING(TS.FORDQTY / MSP.PACKQTY)), '0/0') AS BOXCNT from WSHPIT SH inner join ( select t.COMPKEY, t.WAREKEY, t.OWNERKY, t.ALLGRKY, t.PICKTYP, t.SHPDCKY, t.SHPDCIT, t.COOUTKY, t.COOUTIT, t.SKUMKEY, t.SKUDESC, SUM(t.TCMPQTY) as TCMPQTY, t.FORDQTY from WTAKIT t where t.COMPKEY = #{compkey} and t.WAREKEY = #{warekey} and t.DOCCATE = '500' and t.DOCTYPE = '530' and t.ALLGRKY = #{allgrky} and t.PICKTYP = #{picktyp}
and t.COOUTKY = #{cooutky}
group by ALLGRKY, COOUTKY, COOUTIT ) TS on SH.COMPKEY = TS.COMPKEY and SH.WAREKEY = TS.WAREKEY and SH.OWNERKY = TS.OWNERKY and SH.COOUTKY = TS.COOUTKY and SH.COOUTIT = TS.COOUTIT inner join ( select MS.COMPKEY, MS.WAREKEY, MS.OWNERKY, MS.SKUMKEY, MS.SKUDESC, MS.SUOMKEY, MS.UPCCODE, MS.TRUNTYP, MP.PACKKEY, MP.PACKQTY from MSKUWC MS left outer join MPAKMA MP on MP.COMPKEY = MS.COMPKEY and MP.WAREKEY = MS.WAREKEY and MP.TRUNTYP = MS.TRUNTYP and MP.PACKKEY = MS.PACKKEY ) MSP on SH.COMPKEY = MSP.COMPKEY and SH.WAREKEY = MSP.WAREKEY and SH.SKUMKEY = MSP.SKUMKEY where SH.COMPKEY = #{compkey} and SH.WAREKEY = #{warekey} and TS.PICKTYP = #{picktyp}
and TS.ALLGRKY in
#{item}
and TS.ALLGRKY = #{allgrky}
and TS.COOUTKY = #{cooutky}
and SH.SHPITST = #{shpitst}
and SH.DESTKEY = #{destkey}

/* getShipOrderItem */
select COUNT(A.SKU) as SKUNCNT 
	 , sum(A.STOCK) as STOTQTY
from (
	select count(WT.SKUMKEY) as SKU
		 , sum(WT.FORDQTY)   as STOCK
	  from WTAKIT WT 
	  left outer join WSHPIT WS
		on WT.COMPKEY = WS.COMPKEY
	   and WT.WAREKEY = WS.WAREKEY
	   and WT.COOUTKY = WS.COOUTKY 
	   and WT.COOUTIT = WS.COOUTIT  
	   and WS.SHPDCKY = WS.SHPDCKY
	   and WT.SHPDCIT = WS.SHPDCIT 
	 WT.COMPKEY = #{compkey}
 	    and WT.WAREKEY = #{warekey}
 	    and WT.ALLGRKY = #{allgrky}
		and WT.TASKSTS not in ('CANCEL')

		and WT.COOUTKY = #{cooutky}



















		   and WT.OERETKY in

			#{orditem}



   	   	   and WS.DESTKEY = #{destkey}

	group by WT.SKUMKEY

) A

/* getWmPrintLogCount */
select count(PRINTSQ) as PRINTCOUNT
  from SPRTHI
where COMPKEY = #{compkey}


			and ALLGRKY = #{allgrky}
			and COOUTKY = #{cooutky}


			and SHPDCKY = #{allgrky}




			and ALLGRKY = #{allgrky}


			and SHPDCKY = #{allgrky}



		and TASKOKY = #{taskoky}


		and PHYSOKY = #{physoky}



			and ALLGRKY = #{allgrky}
			and PROGRID = #{progrid}
			and COOUTKY in 

			 #{item}



			and SHPDCKY = #{allgrky}
			and PROGRID = #{progrid}

{ 
	/* wmAddPrintList */
	CALL SP_SY_SPRTHI (#{compkey}, #{warekey}, #{doccate},
	#{doctype},
	#{progrid}, #{dochkey}, #{docitem}, #{loguser},
	#{omsgkey, mode=OUT, jdbcType=VARCHAR}, #{oresult, mode=OUT, jdbcType=VARCHAR})		
}
